import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const ProductForm = () => {
    const [formData, setFormData] = useState({
        name: '',
        price: '',
        stock: '',
        description: '',
        image: '',
    });
    const navigate = useNavigate();

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleFileChange = (e) => {
        const file = e.target.files[0];
        const reader = new FileReader();

        reader.onloadend = () => {
            setFormData({ ...formData, image: reader.result }); // Save base64 string
        };

        if (file) {
            reader.readAsDataURL(file);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        try {
            await axios.post('http://localhost:5000/api/products/add', formData);
            navigate('/'); // Redirect to Product Table
        } catch (error) {
            alert('Failed to add product');
        }
    };

    return (
        <form onSubmit={handleSubmit}>
            <h2>Add Product</h2>
            <input name="name" type="text" placeholder="Name" value={formData.name} onChange={handleChange} required />
            <input name="price" type="number" placeholder="Price" value={formData.price} onChange={handleChange} required />
            <input name="stock" type="number" placeholder="Stock" value={formData.stock} onChange={handleChange} required />
            <textarea name="description" placeholder="Description" value={formData.description} onChange={handleChange} required />
            <input name="image" type="file" onChange={handleFileChange} required />
            <button type="submit">Add Product</button>
        </form>
    );
};

export default ProductForm;
